const config = {
  departments: {
    "Software": { slack: "YOUR_SOFTWARE_SLACK_CHANNEL_ID", jira: "YOUR_SOFTWARE_JIRA_PROJECT_KEY" },
    "Marketing": { slack: "YOUR_MARKETING_SLACK_CHANNEL_ID", jira: "YOUR_MKT_JIRA_PROJECT_KEY" },
    "Finance": { slack: "YOUR_FINANCE_SLACK_CHANNEL_ID", jira: "YOUR_FIN_JIRA_PROJECT_KEY" },
    "Project": { slack: "YOUR_PROJECT_SLACK_CHANNEL_ID", jira: "YOUR_PROJ_JIRA_PROJECT_KEY" }
  },
  componentMap: {
    "FrontEnd": "YOUR_FRONTEND_COMPONENT_ID",
    "BackEnd": "YOUR_BACKEND_COMPONENT_ID",
    "Mobile": "YOUR_MOBILE_COMPONENT_ID",
    "UI/UX": "YOUR_UIUX_COMPONENT_ID",
    "Tester": "YOUR_TESTER_COMPONENT_ID",
    "Project Manager": "YOUR_PM_COMPONENT_ID",
    "Business Analyst": "YOUR_BA_COMPONENT_ID",
    "Scrum Master": "YOUR_SM_COMPONENT_ID"
  },
  teams: {
    "FrontEnd": "your-frontend-repo-name",
    "BackEnd": "your-backend-repo-name",
    "Mobile": "your-mobile-repo-name",
    "UI/UX": "your-design-repo-name",
    "Tester": "your-qa-repo-name"
  }
};

const item = $input.item.json;

const deptConfig = config.departments[item.Department] || { slack: "YOUR_GENERAL_SLACK_CHANNEL_ID", jira: "YOUR_DEFAULT_JIRA_PROJECT_KEY" };
const selectedComponentId = config.componentMap[item.Team];

return {
  ...item,
  targetSlack: deptConfig.slack,
  targetJira: deptConfig.jira,
  targetComponentIds: selectedComponentId ? [selectedComponentId] : [],
  targetRepo: config.teams[item.Team] || "your-general-repo-name",
  targetGithubUser: item["GitHub Username"],
  isSoftware: item.Department === "Software"
};
